'use client';
function getAxiomCompliance(dbAvailable, isTickRunning) {
    const subsystems = [
        'MathEngine',
        'ChunkEngine',
        'TickEngine',
        'CombatSystem',
        'LootGenerator',
        'EconomicAggregator',
        'HierarchyValidator',
        'MatrixAccounting',
        'TransactionWrapper',
        'Routes',
        'Database'
    ];
    const matrix = subsystems.map((sub)=>{
        const entry = {
            subsystem: sub,
            energy: 'PASS',
            erosion: 'PASS',
            punctuation: 'PASS',
            recursion: [
                'MathEngine',
                'ChunkEngine',
                'EconomicAggregator',
                'TickEngine'
            ].includes(sub) ? 'PASS' : 'N/A',
            duality: 'PASS',
            status: 'COMPLIANT'
        };
        if (sub === 'Database') {
            entry.energy = dbAvailable ? 'PASS' : 'WARN';
            entry.status = dbAvailable ? 'COMPLIANT' : 'DEGRADED';
        }
        if (sub === 'TickEngine') {
            entry.punctuation = isTickRunning ? 'PASS' : 'WARN';
            entry.status = isTickRunning ? 'COMPLIANT' : 'IDLE';
        }
        return entry;
    });
    const allCompliant = matrix.every((m)=>m.status === 'COMPLIANT' || m.status === 'IDLE');
    return {
        success: true,
        timestamp: new Date().toISOString(),
        overallStatus: allCompliant ? 'COMPLIANT' : 'PARTIAL',
        matrix
    };
}
